def flatten(nested: list) -> list:
    result = []
    for item in nested:
        if isinstance(item, list):
            result.extend(flatten(item))
        else:
            result.append(item)
    return result


if __name__ == "__main__":
    data = [1, [2, 3], [4, [5, 6]], 7]
    print(flatten(data))

def chunk(items: list, size: int) -> list:
    return [items[i:i + size] for i in range(0, len(items), size)]


if __name__ == "__main__":
    data = list(range(10))
    print(chunk(data, 3))

